        { id: "spring_41", question: "What is Spring Integration?", explanation: "Extends Spring to support messaging patterns for integrating different systems.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_42", question: "What is @Scheduled?", explanation: "Used to run a method periodically based on a fixed rate, delay, or cron expression.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_43", question: "What is @Async?", explanation: "Tells Spring to run the method in a separate thread asynchronously.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_44", question: "What is Spring JDBC?", explanation: "A layer that simplifies JDBC usage by handling resource management and exception translation.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_45", question: "What is Hibernate in Spring context?", explanation: "An ORM (Object-Relational Mapping) framework that Spring Data JPA uses by default.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_46", question: "What is @Entity?", explanation: "Marks a class as a persistent entity to be mapped to a database table.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_47", question: "What is @Id and @GeneratedValue?", explanation: "Marks the primary key and defines how its value should be generated.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_48", question: "Difference between L1 and L2 cache in Hibernate?", explanation: "L1 is session-level (mandatory); L2 is session-factory level (optional/global).", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_49", question: "What is N+1 query problem?", explanation: "A performance issue where multiple extra queries are made to fetch related child entities instead of one JOIN.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_50", question: "What is FetchType.LAZY vs EAGER?", explanation: "LAZY loads associated data only when accessed; EAGER loads everything upfront.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_51", question: "What is Spring Boot CLI?", explanation: "A command-line tool that lets you create Spring apps using Groovy scripts quickly.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_52", question: "How to change default port in Spring Boot?", explanation: "Set 'server.port=9090' in application.properties.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_53", question: "What is @JoinColumn?", explanation: "Used to define the physical mapping of a foreign key column in a database table.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_54", question: "What is the use of H2 database?", explanation: "An in-memory relational database useful for testing and rapid prototyping.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_55", question: "What is MockMvc?", explanation: "Used in Spring tests to perform HTTP requests against controllers without starting a full server.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_56", question: "@WebMvcTest vs @SpringBootTest?", explanation: "WebMvcTest only loads web-related beans; SpringBootTest loads the full application context.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_57", question: "What is @MockBean?", explanation: "Used in tests to add a mock object to the Spring ApplicationContext, replacing any existing bean.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_58", question: "What is RestTemplate vs WebClient?", explanation: "RestTemplate is blocking (synchronous); WebClient is reactive/non-blocking (recommended now).", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_59", question: "What is Spring WebFlux?", explanation: "Spring's reactive-stack web framework built on Project Reactor for non-blocking apps.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_60", question: "What is a Flux and Mono in WebFlux?", explanation: "Mono is for 0 or 1 item; Flux is for 0 to N items in a stream.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_61", question: "What is CI/CD in Spring Boot context?", explanation: "Automated pipelines to test and deploy Spring apps (Jenkins, GitHub Actions).", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_62", question: "What is CSRF protection in Spring Security?", explanation: "Prevents Cross-Site Request Forgery by requiring a token for state-changing requests.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_63", question: "How to secure a method in Spring Boot?", explanation: "Use @PreAuthorize or @Secured annotations with roles/permissions.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_64", question: "What is OAuth2?", explanation: "An industry-standard protocol for authorization, allowing apps to access user data safely.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_65", question: "What is JWT (JSON Web Token)?", explanation: "A compact way to transmit information between parties as a JSON object, used for stateless auth.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_66", question: "What is Spring Cloud Config?", explanation: "Centralized configuration management for all microservices in a cluster.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_67", question: "What is a Circuit Breaker (Resilience4j)?", explanation: "Prevents a failure in one microservice from cascading and taking down the whole system.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_68", question: "What is Spring Cloud Gateway?", explanation: "Provides an API Gateway for routing requests to various microservices.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_69", question: "What is @EnableBatchProcessing?", explanation: "Configures Spring Batch's infrastructure (job repo, job launcher) automatically.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_70", question: "What is a Job, Step, and Tasklet in Spring Batch?", explanation: "Job is the full process; Step is a phase; Tasklet is a simple task within a step.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_71", question: "What is Logback in Spring Boot?", explanation: "The default logging framework provided by Spring Boot.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_72", question: "What is externalizing configuration?", explanation: "Keeping config outside the code (env vars, properties files) so it can change without rebuild.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_73", question: "What is @Lazy annotation?", explanation: "Delays the creation of a bean until it is actually needed for the first time.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_74", question: "What is @Scope(\"singleton\")?", explanation: "The default scope where only one instance of the bean exists per Spring container.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_75", question: "What is @Scope(\"prototype\")?", explanation: "A new bean instance is created every time it's requested from the container.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_76", question: "What is BeanPostProcessor?", explanation: "An interface used to modify or wrap a bean instance after its initialization.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_77", question: "What is CommandLineRunner?", explanation: "An interface used to run a block of code immediately after the Spring app starts.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_78", question: "What is Spring Boot Runner vs Main?", explanation: "Main starts the context; Runners execute specific logic once context is ready.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_79", question: "How to disable specific Auto-configuration?", explanation: "Use the 'exclude' attribute in @SpringBootApplication.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_80", question: "What is DispatcherServlet?", explanation: "The front controller that coordinates all HTTP requests in a Spring MVC app.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_81", question: "What is ViewResolver?", explanation: "Determines which physical view template (JSP, Thymeleaf) to use based on a name string.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_82", question: "What is Thymeleaf?", explanation: "A server-side Java template engine for web and standalone environments.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_83", question: "What is @ModelAttribute?", explanation: "Used to bind a method parameter or method return value to a named model attribute in web apps.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_84", question: "What is @SessionAttributes?", explanation: "Used to store model attributes in the HTTP session for use across multiple requests.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_85", question: "What is Spring Context Hierarchy?", explanation: "Allows nesting of application contexts (e.g., Parent Root Context + Child Servlet Context).", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_86", question: "What is @Lookup annotation?", explanation: "Used for Method Injection, allowing a singleton to get a fresh instance of a prototype bean.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_87", question: "What is BeanDefinition?", explanation: "An object that contains metadata about a bean (class name, scope, arguments).", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_88", question: "What is Spring SPI (Service Provider Interface)?", explanation: "Mechanism used by Spring to discover extensions and auto-config classes.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_89", question: "What is Spring Lifecycle Callback?", explanation: "Implementing InitializingBean or DisposableBean interfaces for lifecycle control.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_90", question: "What is @AliasFor?", explanation: "Used to create an alias for an annotation attribute, keeping them synchronized.", difficulty: "Hard", category: "Spring Boot" },
        { id: "spring_91", question: "Difference between WAR and JAR in Spring Boot?", explanation: "JAR is self-contained (embedded server); WAR requires external container installation.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_92", question: "What is Spring Boot Maven Plugin?", explanation: "Helps in packaging the app as an executable fat-jar or war.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_93", question: "What is @ResponseStatus?", explanation: "Used to customize the HTTP status code returned by a controller method.", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_94", question: "What is Spring Validation?", explanation: "Uses Java Bean Validation (JSR-303) to validate object graphs automatically.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_95", question: "What is @Profile(\"!prod\")?", explanation: "The exclamation mark excludes the profile, meaning it runs in any environment EXCEPT production.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_96", question: "What is Spring Data Query Method?", explanation: "Creating database queries just by naming the method in a certain pattern (findBy...).", difficulty: "Easy", category: "Spring Boot" },
        { id: "spring_97", question: "What is @Query annotation?", explanation: "Used to write custom JPQL or Native SQL queries inside an interface.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_98", question: "What is Spring Cache(@Cacheable)?", explanation: "A simple way to add caching to methods, storing results based on input parameters.", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_99", question: "What is @CacheEvict?", explanation: "Used to remove specific entries (or all) from a cache (e.g., after an update).", difficulty: "Medium", category: "Spring Boot" },
        { id: "spring_100", question: "What is Spring Boot WhiteLabel Error Page?", explanation: "The default generic error page provided by Spring Boot when no custom handler exists.", difficulty: "Easy", category: "Spring Boot" }
